import axios from "axios";
import { Resolver } from "./resolver/Resolver";
import { authHeader_local } from "../constant";

export async function getData(url) {
  let authHeader_local =
    "eyJhbGciOiJIUzUxMiJ9..6-ayJuu_78E1ADHNQnCtq9p_yxQrzpYwz-Xq81Q4LL2HrDLAWy2t6_HNv-LscNnNoD0TlGbf4z2Qr2um4RQx7A";
  const headers = {
    Authorization: `Bearer ${authHeader_local}`,
  };
  const response = await Resolver(axios.get(url, { headers }));
  return response.data;
}
